// Twilio inbound SMS POSTs form-encoded data.
// n8n parses it into $json directly or nested under $json.body.
const raw = $input.item.json.body || $input.item.json;

const from   = (raw.From       || '').trim();
const to     = (raw.To         || '').trim();
const body   = (raw.Body       || '').trim();
const msgSid = (raw.MessageSid || '').trim();

return [{ json: { from, to, body, msgSid } }];

// Classify the reply intent and build the Supabase PATCH payload.
// Detects: CALL, CALL ME (case-insensitive, trimmed)
const body = ($json.body || '').trim();
const isCallback = /^call( me)?$/i.test(body);

return [{
  json: {
    from:    $json.from,
    to:      $json.to,
    intent:  isCallback ? 'callback' : 'other',
    updatePayload: {
      reply_received:     true,
      reply_intent:       isCallback ? 'callback' : 'other',
      callback_requested: isCallback
    }
  }
}];

// Safe extraction of call log ID from Supabase array response.
// Returns [] (stops execution) if no matching call log is found.
const result = $input.item.json;
const rows = Array.isArray(result) ? result : (result.id ? [result] : []);

if (!rows[0] || !rows[0].id) {
  // No call log found for this phone number — silently drop
  return [];
}

return [{
  json: {
    callLogId:     rows[0].id,
    from:          $('Detect Intent').item.json.from,
    intent:        $('Detect Intent').item.json.intent,
    updatePayload: $('Detect Intent').item.json.updatePayload
  }
}];
